// Renders the appropriate input for a column's type.
// col shape: { key, header, type?, options? }
// type: 'text' (default) | 'date' | 'textarea' | 'number' | 'url' | 'select'
export default function CellEditor({ col, value, onChange, onCommit, onCancel }) {
  const type = col.type || 'text'

  function handleKeyDown(e) {
    if (e.key === 'Escape') { e.preventDefault(); onCancel() }
    if (e.key === 'Enter' && type !== 'textarea') { e.preventDefault(); onCommit() }
  }

  const inputClass =
    'w-full px-2 py-1 border border-primary rounded text-sm focus:outline-none focus:ring-1 focus:ring-primary bg-white dark:bg-gray-800 dark:text-gray-100'

  if (type === 'textarea') {
    return (
      <textarea
        autoFocus
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onBlur={() => onCommit()}
        onKeyDown={handleKeyDown}
        rows={3}
        className={`${inputClass} resize-none`}
      />
    )
  }

  if (type === 'select') {
    return (
      <select
        autoFocus
        value={value}
        onChange={(e) => { onChange(e.target.value); onCommit(e.target.value) }}
        onKeyDown={handleKeyDown}
        className={inputClass}
      >
        <option value="">—</option>
        {(col.options || []).map((opt) => (
          <option key={opt} value={opt}>{opt}</option>
        ))}
      </select>
    )
  }

  return (
    <input
      autoFocus
      type={type}
      value={value}
      onChange={(e) => onChange(e.target.value)}
      onBlur={() => onCommit()}
      onKeyDown={handleKeyDown}
      className={inputClass}
    />
  )
}

import { describe, it, expect, vi } from 'vitest'
import { render, screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import CellEditor from './CellEditor'

function makeProps(overrides = {}) {
  return {
    onChange: vi.fn(),
    onCommit: vi.fn(),
    onCancel: vi.fn(),
    ...overrides,
  }
}

describe('CellEditor', () => {
  it('renders text input by default', () => {
    render(<CellEditor col={{ key: 'name', header: 'Name' }} value="foo" {...makeProps()} />)
    expect(document.querySelector('input[type="text"]')).toBeInTheDocument()
  })

  it('renders text input for type text', () => {
    render(<CellEditor col={{ key: 'name', header: 'Name', type: 'text' }} value="foo" {...makeProps()} />)
    expect(document.querySelector('input[type="text"]')).toBeInTheDocument()
  })

  it('renders date input for type date', () => {
    render(<CellEditor col={{ key: 'date', header: 'Date', type: 'date' }} value="2024-01-15" {...makeProps()} />)
    expect(document.querySelector('input[type="date"]')).toBeInTheDocument()
  })

  it('renders textarea for type textarea', () => {
    render(<CellEditor col={{ key: 'notes', header: 'Notes', type: 'textarea' }} value="long text" {...makeProps()} />)
    expect(screen.getByRole('textbox').tagName).toBe('TEXTAREA')
  })

  it('renders number input for type number', () => {
    render(<CellEditor col={{ key: 'amount', header: 'Amount', type: 'number' }} value="42" {...makeProps()} />)
    expect(document.querySelector('input[type="number"]')).toBeInTheDocument()
  })

  it('renders url input for type url', () => {
    render(<CellEditor col={{ key: 'url', header: 'URL', type: 'url' }} value="https://example.com" {...makeProps()} />)
    expect(document.querySelector('input[type="url"]')).toBeInTheDocument()
  })

  it('renders select with options for type select', () => {
    render(
      <CellEditor
        col={{ key: 'status', header: 'Status', type: 'select', options: ['Active', 'Done'] }}
        value="Active"
        {...makeProps()}
      />
    )
    expect(screen.getByRole('combobox')).toBeInTheDocument()
    expect(screen.getByText('Active')).toBeInTheDocument()
    expect(screen.getByText('Done')).toBeInTheDocument()
  })

  it('calls onCommit on Enter for text input', async () => {
    const user = userEvent.setup()
    const props = makeProps()
    render(<CellEditor col={{ key: 'name', header: 'Name' }} value="foo" {...props} />)
    await user.keyboard('{Enter}')
    expect(props.onCommit).toHaveBeenCalled()
  })

  it('calls onCancel on Escape', async () => {
    const user = userEvent.setup()
    const props = makeProps()
    render(<CellEditor col={{ key: 'name', header: 'Name' }} value="foo" {...props} />)
    await user.keyboard('{Escape}')
    expect(props.onCancel).toHaveBeenCalled()
  })

  it('calls onCommit on blur', async () => {
    const user = userEvent.setup()
    const props = makeProps()
    render(
      <div>
        <CellEditor col={{ key: 'name', header: 'Name' }} value="foo" {...props} />
        <button>other</button>
      </div>
    )
    await user.click(screen.getByText('other'))
    expect(props.onCommit).toHaveBeenCalled()
  })

  it('does not commit on Enter for textarea', async () => {
    const user = userEvent.setup()
    const props = makeProps()
    render(<CellEditor col={{ key: 'notes', header: 'Notes', type: 'textarea' }} value="text" {...props} />)
    await user.keyboard('{Enter}')
    expect(props.onCommit).not.toHaveBeenCalled()
  })

  it('calls onCommit with value immediately on select change', async () => {
    const user = userEvent.setup()
    const props = makeProps()
    render(
      <CellEditor
        col={{ key: 'status', header: 'Status', type: 'select', options: ['Active', 'Done'] }}
        value="Active"
        {...props}
      />
    )
    await user.selectOptions(screen.getByRole('combobox'), 'Done')
    expect(props.onCommit).toHaveBeenCalledWith('Done')
  })

  it('calls onChange as user types', async () => {
    const user = userEvent.setup()
    const props = makeProps()
    render(<CellEditor col={{ key: 'name', header: 'Name' }} value="" {...props} />)
    await user.type(document.querySelector('input'), 'hello')
    expect(props.onChange).toHaveBeenCalled()
  })
})

import { describe, it, expect, vi } from 'vitest'
import { render, screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import DataTable, { formatCellValue } from './DataTable'

const columns = [
  { key: 'name', header: 'Name' },
  { key: 'status', header: 'Status' },
]

const rows = [
  { id: '1', name: 'Task A', status: 'Done' },
  { id: '2', name: 'Task B', status: 'Pending' },
]

describe('DataTable', () => {
  it('renders column headers', () => {
    render(<DataTable columns={columns} rows={rows} onUpdate={() => {}} onDelete={() => {}} />)
    expect(screen.getByText('Name')).toBeInTheDocument()
    expect(screen.getByText('Status')).toBeInTheDocument()
  })

  it('renders row data', () => {
    render(<DataTable columns={columns} rows={rows} onUpdate={() => {}} onDelete={() => {}} />)
    expect(screen.getByText('Task A')).toBeInTheDocument()
    expect(screen.getByText('Task B')).toBeInTheDocument()
  })

  it('allows inline editing on cell click', async () => {
    const user = userEvent.setup()
    const onUpdate = vi.fn()
    render(<DataTable columns={columns} rows={rows} onUpdate={onUpdate} onDelete={() => {}} />)

    await user.click(screen.getByText('Task A'))
    const input = screen.getByDisplayValue('Task A')
    await user.clear(input)
    await user.type(input, 'Updated')
    await user.keyboard('{Enter}')

    expect(onUpdate).toHaveBeenCalledWith('1', 'name', 'Updated')
  })

  it('calls onDelete when delete button clicked', async () => {
    const user = userEvent.setup()
    const onDelete = vi.fn()
    render(<DataTable columns={columns} rows={rows} onUpdate={() => {}} onDelete={onDelete} />)

    const deleteButtons = screen.getAllByLabelText('Delete row')
    await user.click(deleteButtons[0])
    expect(onDelete).toHaveBeenCalledWith('1')
  })

  it('filters rows based on search', async () => {
    const user = userEvent.setup()
    render(<DataTable columns={columns} rows={rows} onUpdate={() => {}} onDelete={() => {}} />)

    const search = screen.getByPlaceholderText('Search...')
    await user.type(search, 'Task B')

    expect(screen.queryByText('Task A')).not.toBeInTheDocument()
    expect(screen.getByText('Task B')).toBeInTheDocument()
  })

  it('shows empty state when no rows', () => {
    render(<DataTable columns={columns} rows={[]} onUpdate={() => {}} onDelete={() => {}} />)
    expect(screen.getByText(/no data/i)).toBeInTheDocument()
  })

  it('renders date input when editing a date column', async () => {
    const user = userEvent.setup()
    const dateColumns = [{ key: 'date', header: 'Date', type: 'date' }]
    const dateRows = [{ id: '1', date: '2024-01-15' }]
    render(<DataTable columns={dateColumns} rows={dateRows} onUpdate={() => {}} onDelete={() => {}} />)
    await user.click(screen.getByText('Jan 15, 2024'))
    expect(document.querySelector('input[type="date"]')).toBeInTheDocument()
  })

  it('renders textarea when editing a textarea column', async () => {
    const user = userEvent.setup()
    const textColumns = [{ key: 'notes', header: 'Notes', type: 'textarea' }]
    const textRows = [{ id: '1', notes: 'some notes' }]
    render(<DataTable columns={textColumns} rows={textRows} onUpdate={() => {}} onDelete={() => {}} />)
    await user.click(screen.getByText('some notes'))
    const textboxes = screen.getAllByRole('textbox')
    expect(textboxes.some((el) => el.tagName === 'TEXTAREA')).toBe(true)
  })

  it('renders select when editing a select column', async () => {
    const user = userEvent.setup()
    const selectColumns = [{ key: 'status', header: 'Status', type: 'select', options: ['Active', 'Done'] }]
    const selectRows = [{ id: '1', status: 'Active' }]
    render(<DataTable columns={selectColumns} rows={selectRows} onUpdate={() => {}} onDelete={() => {}} />)
    await user.click(screen.getAllByText('Active')[0])
    expect(screen.getByRole('combobox')).toBeInTheDocument()
  })

  it('formats date values in display', () => {
    const dateColumns = [{ key: 'date', header: 'Date', type: 'date' }]
    const dateRows = [{ id: '1', date: '2024-01-15' }]
    render(<DataTable columns={dateColumns} rows={dateRows} onUpdate={() => {}} onDelete={() => {}} />)
    expect(screen.getByText('Jan 15, 2024')).toBeInTheDocument()
  })
})

describe('formatCellValue', () => {
  it('returns empty string for falsy value', () => {
    expect(formatCellValue({ key: 'date', type: 'date' }, '')).toBe('')
    expect(formatCellValue({ key: 'date', type: 'date' }, null)).toBe('')
  })

  it('formats a valid date string', () => {
    expect(formatCellValue({ key: 'date', type: 'date' }, '2024-01-15')).toBe('Jan 15, 2024')
  })

  it('returns original value for unparseable date', () => {
    expect(formatCellValue({ key: 'date', type: 'date' }, 'not-a-date')).toBe('not-a-date')
  })

  it('returns string value for non-date types', () => {
    expect(formatCellValue({ key: 'name', type: 'text' }, 'hello')).toBe('hello')
  })
})

